"use client"

import type { SC } from "@/lib/event-styles"

export type ProgramLayout = "centered" | "timeline"

export interface ProgramItem {
  id?: string
  time: string
  title?: string
  description: string
  iconId?: string
  image_url?: string | null
  imagePosX?: number
}

